let globalConfig=[],adminConfig=[],healthData=null,currentRawData='',currentExtractMode=false,selectedRegions=[],stResults=[],isTesting=false,abortSpeedtest=false,artifactPreviewText='',pendingImportConfig=null,pendingSaveSnapshot='',pendingSaveChanges=null,pendingSaveArchiveCount=0,pendingArchiveRestore=null;
const SPEEDTEST_HISTORY_KEY='bestip-speedtest-history-v1';
const DEFAULT_NIP_DOMAIN='nip.lfree.org';
const SPEEDTEST_COMPAT_NOTE='浏览器无法可靠测 Cloudflare 裸 IP；本地 TCP 测速 tcp-speedtest 已替换为浏览器延迟测试，真实速度请用 CloudflareSpeedTest / cfst。';
const countLines=text=>extractUsefulLines(String(text||'')).length;
function updateResultLines(){const el=$('result-lines');if(el)el.textContent=countLines($('ip-display')?.value||'')+' 行'}
function setResult(text){const area=$('ip-display');if(area)area.value=text;updateResultLines()}
function switchPage(page){document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));$('page-'+page).classList.add('active');document.querySelectorAll('.nav-item').forEach(b=>b.classList.toggle('active',b.dataset.page===page));const [title,sub]=PAGE_META[page];$('page-title').textContent=title;$('page-subtitle').textContent=sub;if(page==='speedtest')openSpeedtestPage();if(page==='admin')openAdminPage()}
function extractUsefulLines(text){return text.split(/\r?\n/).map(s=>s.trim()).filter(s=>s&&!s.startsWith('//')&&!s.startsWith('/*'))}
async function loadNav(){const res=await fetch('/api/config');globalConfig=await res.json();renderMainNav();adminConfig=JSON.parse(JSON.stringify(globalConfig))}
function getSourceSearchTerm(){return ($('source-search')?.value||'').trim().toLowerCase()}
function sourceMatches(group,node,term){return !term||group.groupName.toLowerCase().includes(term)||node.ID.toLowerCase().includes(term)||(node.url||'').toLowerCase().includes(term)}
function renderMainNav(){const main=$('main-nav'),summary=$('source-search-summary'),term=getSourceSearchTerm();main.innerHTML='';$('sub-nav').innerHTML='';let groups=0,nodes=0;for(const [i,g] of globalConfig.entries()){const matched=(g.nodes||[]).filter(node=>sourceMatches(g,node,term));if(term&&!matched.length)continue;groups++;nodes+=term?matched.length:(g.nodes||[]).length;const b=document.createElement('button');b.className='node-btn';b.textContent=term?`${g.groupName} (${matched.length})`:g.groupName;b.onclick=()=>{document.querySelectorAll('#main-nav button').forEach(x=>x.classList.remove('active'));b.classList.add('active');renderSubNav(i)};main.appendChild(b)}if(summary)summary.textContent=term?`匹配 ${groups} 个分类、${nodes} 条线路。`:'未输入搜索词，显示全部分类。';if(term&&!groups)$('sub-nav').innerHTML='<span class="hint">没有匹配的线路。</span>'}
function renderSubNav(i){const sub=$('sub-nav'),term=getSourceSearchTerm(),group=globalConfig[i];sub.innerHTML='';const categoryWrap=document.createElement('div');categoryWrap.className='category-actions';categoryWrap.innerHTML=`<b>${esc(group.groupName)}</b><button class="node-btn export" type="button">导出分类</button>`;categoryWrap.querySelector('button').onclick=()=>exportCategory(group.groupName);sub.appendChild(categoryWrap);const nodes=(group.nodes||[]).filter(node=>sourceMatches(group,node,term));if(!nodes.length){sub.innerHTML='<span class="hint">该分类下没有匹配的线路。</span>';return}for(const node of nodes){const wrap=document.createElement('span');wrap.className='node-actions';const b=document.createElement('button');b.className='node-btn';b.textContent=node.ID;b.title=node.url||'';b.onclick=()=>{document.querySelectorAll('#sub-nav .node-btn').forEach(x=>x.classList.remove('active'));b.classList.add('active');currentExtractMode=!!node.extract;showSourceInfo(node.ID);loadIPs(node.ID)};const raw=document.createElement('button');raw.className='node-btn';raw.textContent='原始';raw.title='查看该源原始返回';raw.onclick=()=>viewRawSource(node.ID);const parsed=document.createElement('button');parsed.className='node-btn';parsed.textContent='解析';parsed.title='查看该源解析后的标准结果';parsed.onclick=()=>viewParsedSource(node.ID);const ex=document.createElement('button');ex.className='node-btn export';ex.textContent='导出';ex.title='导出该单源结果';ex.onclick=()=>exportSingleSource(node.ID);wrap.appendChild(b);wrap.appendChild(raw);wrap.appendChild(parsed);wrap.appendChild(ex);sub.appendChild(wrap)}}
async function loadIPs(id){setResult('正在拉取专属节点数据...');try{const res=await fetch('/api/ips?ID='+encodeURIComponent(id));currentRawData=await res.text();renderDisplay()}catch(e){setResult('请求异常：'+e.message)}}
function renderDisplay(){let text=currentRawData.trim();if(currentExtractMode&&text&&!text.includes('://')){try{text=new TextDecoder().decode(Uint8Array.from(atob(text),c=>c.charCodeAt(0)))}catch{}}setResult(extractUsefulLines(text).join('\n')||text||'无数据')}
function showSourceInfo(id){if(!healthData){$('selected-source-info').textContent='源状态未检测；可先到仪表盘检测全部真实源。';return}const item=healthData.results.find(r=>r.id===id);if(!item){$('selected-source-info').textContent='未找到该源检测记录。';return}$('selected-source-info').innerHTML=`<span class="status-dot ${item.ok?'ok-dot':'bad-dot'}"></span>${item.groupName} / ${item.id}：${item.ok?'可用':'失败'}，${item.format}，${item.lines} 行，${item.ms}ms ${item.error?('，'+esc(item.error)):''}`}
function initRegionGrid(){const grid=$('region-grid');grid.innerHTML='';for(const [code,name] of Object.entries(REGION_MAP)){const el=document.createElement('button');el.className='region-btn';el.id='reg-'+code;el.innerHTML=`<div class="code">${code}</div><div class="name">${name}</div>`;el.onclick=()=>toggleRegion(code);grid.appendChild(el)}}
function toggleRegion(code){const i=selectedRegions.indexOf(code);i>=0?selectedRegions.splice(i,1):selectedRegions.push(code);$('reg-'+code).classList.toggle('active',selectedRegions.includes(code))}
function selectAllRegions(){const all=Object.keys(REGION_MAP);selectedRegions=selectedRegions.length===all.length?[]:all;all.forEach(c=>$('reg-'+c).classList.toggle('active',selectedRegions.includes(c)))}
async function fetchGlobalEdgetunnel(){if(!selectedRegions.length)return alert('请至少选择一个地区');setResult('正在从全球池随机提取...');const limit=$('global-limit').value||0;const res=await fetch('/api/edge_ips?regions='+selectedRegions.join(',')+'&limit='+limit);setResult(await res.text());switchPage('sources')}
async function loadHealth(force=false){if(!force&&healthData)return;const body=$('health-body');body.innerHTML='<tr><td colspan="9" class="hint">正在检测真实源...</td></tr>';const res=await fetch('/api/source-health');healthData=await res.json();const s=healthData.summary;for(const [id,val] of Object.entries({'stat-total':s.total,'stat-ok':s.ok,'stat-failed':s.failed,'stat-lines':s.lines,'top-total':s.total,'top-ok':s.ok,'top-failed':s.failed}))$(id).textContent=val;$('health-time').textContent='最近检测：'+new Date(s.checkedAt).toLocaleString();renderGroupSummary();renderHealthTable()}
function renderGroupSummary(){if(!healthData?.groups)return;const select=$('health-group');const current=select.value;select.innerHTML='<option value="all">全部分类</option>'+healthData.groups.map(g=>`<option value="${esc(g.groupName)}">${esc(g.groupName)} (${g.ok}/${g.total})</option>`).join('');select.value=[...select.options].some(o=>o.value===current)?current:'all';$('group-summary').innerHTML=healthData.groups.map(g=>`<div class="group-pill ${g.failed?'bad':(g.slow?'slow':'')}"><b>${esc(g.groupName)}</b><span>可用 ${g.ok}/${g.total} · 失败 ${g.failed} · 慢源 ${g.slow} · ${g.lines} 行 · 最慢 ${g.maxMs}ms</span></div>`).join('')}
function renderHealthTable(){if(!healthData)return;let rows=[...healthData.results];const filter=$('health-filter').value;const group=$('health-group')?.value||'all';if(group!=='all')rows=rows.filter(r=>r.groupName===group);if(filter==='failed')rows=rows.filter(r=>!r.ok);if(filter==='slow')rows.sort((a,b)=>b.ms-a.ms);const body=$('health-body');body.innerHTML='';if(!rows.length){body.innerHTML='<tr><td colspan="9" class="hint">没有匹配的源。</td></tr>';return}for(const r of rows){const tr=document.createElement('tr');tr.className=!r.ok?'row-failed':(r.ms>5000?'row-slow':'');tr.innerHTML=`<td data-label="状态"><span class="status-dot ${r.ok?'ok-dot':'bad-dot'}"></span>${r.ok?'可用':'失败'}</td><td data-label="分类">${esc(r.groupName)}</td><td data-label="线路">${esc(r.id)}</td><td data-label="格式">${esc(r.format)}</td><td data-label="行数">${r.lines}</td><td data-label="耗时">${r.ms}ms</td><td data-label="URL" class="url-cell" title="${esc(r.url)}">${esc(r.url)}</td><td data-label="错误">${esc(r.error||'')}</td><td data-label="操作"><button class="node-btn" data-recheck="${esc(r.id)}">重测</button></td>`;body.appendChild(tr)}}
async function recheckSource(id){const res=await fetch('/api/source-check?ID='+encodeURIComponent(id));const item=await res.json();if(!res.ok)return alert(item.error||'重测失败');const idx=healthData.results.findIndex(r=>r.id===id);if(idx>=0)healthData.results[idx]=item;renderHealthTable()}
function exportHealth(){if(!healthData)return alert('请先检测真实源');const text=['# 真实源健康检测报告','检测时间：'+new Date(healthData.summary.checkedAt).toLocaleString(),`总数：${healthData.summary.total} 可用：${healthData.summary.ok} 失败：${healthData.summary.failed} 行数：${healthData.summary.lines}`,'',...healthData.results.map(r=>`${r.ok?'✅':'❌'} [${r.groupName}] ${r.id} | ${r.format} | ${r.lines}行 | ${r.ms}ms | ${r.error||r.url}`)].join('\n');downloadBlob(text,`source-health-${stamp()}.md`,'text/markdown;charset=utf-8')}

async function loadArtifacts(){
  const summary=$('artifact-summary'), links=$('artifact-links');
  if(!summary||!links)return;
  try{
    const data=await api('/artifacts/latest/manifest.json');
    if(!data.ok){summary.textContent='暂无数据产物，请先生成';links.innerHTML='';return}
    const files=data.files||[];
    const health=data.health;
    if(health?.summary){
      const s=health.summary;
      summary.textContent=`${files.length} 个文件 · 源 ${s.ok}/${s.sources} 可用 · 原始 ${s.rawLines} 行 · 去重 ${s.deduped} 条 · 生成 ${new Date(health.generatedAt).toLocaleString()}`;
    }else{
      const latest=files.map(f=>f.updatedAt).sort().at(-1);
      summary.textContent=`${files.length} 个文件，更新时间 ${latest?new Date(latest).toLocaleString():'未知'}`;
    }
    links.innerHTML=files.map(f=>`<span class="artifact-item"><button class="artifact-preview-btn" data-artifact-preview="${esc(f.name)}">预览</button><a href="/artifacts/latest/${encodeURIComponent(f.name)}" target="_blank" title="${f.size} bytes">${esc(f.name)}</a></span>`).join('');
  }catch(e){summary.textContent='读取产物失败：'+e.message}
}
async function previewArtifact(name){
  const box=$('artifact-preview'), title=$('artifact-preview-title'), body=$('artifact-preview-body'), open=$('btn-artifact-open');
  if(!box||!title||!body||!open)return;
  const url='/artifacts/latest/'+encodeURIComponent(name);
  box.hidden=false;
  title.textContent='正在读取 '+name+' ...';
  body.textContent='加载中...';
  open.href=url;
  try{
    const res=await fetch(url);
    if(!res.ok)throw new Error(await res.text()||res.statusText);
    const text=await res.text();
    const lines=text.split(/\r?\n/);
    const shown=lines.slice(0,200).join('\n');
    artifactPreviewText=shown;
    title.textContent=`${name} · 预览前 ${Math.min(lines.length,200)} / ${lines.length} 行`;
    body.textContent=shown+(lines.length>200?'\n\n……已截断，仅预览前 200 行。':'');
  }catch(e){
    artifactPreviewText='';
    title.textContent=name+' · 读取失败';
    body.textContent=e.message;
  }
}
async function copyArtifactPreview(){
  if(!artifactPreviewText)return alert('请先预览一个产物文件');
  await navigator.clipboard.writeText(artifactPreviewText);
  toast('已复制当前预览内容');
}
async function buildDataset(){
  const btn=$('btn-build-dataset');
  if(btn)btn.disabled=true;
  toast('正在生成数据产物，可能需要几十秒...');
  try{
    const data=await api('/api/build-dataset');
    if(!data.ok||data.result?.ok!==true)throw new Error(data.error||'生成失败');
    const s=data.result.summary||{};
    toast(`生成完成：${s.deduped??'-'} 条，耗时 ${Math.round((data.ms||0)/1000)} 秒`);
    await loadArtifacts();
  }catch(e){alert('生成数据产物失败：'+e.message)}
  finally{if(btn)btn.disabled=false}
}

async function loadCacheStatus(){try{const data=await api('/api/cache-status');const el=$('cache-status');if(!el)return;el.textContent='缓存项：'+data.entries.length+' 个'+(data.entries.length?'，默认缓存 30 分钟，点“刷新健康检测”可强制刷新。':'');}catch(e){}}
async function clearCache(){try{const res=await fetch('/api/cache-clear',{method:'POST',headers:adminHeaders()});const text=await res.text();const data=text?JSON.parse(text):{};if(!res.ok)throw new Error(data.error||text||res.statusText);toast('已清空缓存 '+data.cleared+' 项');loadCacheStatus();}catch(e){alert('清空缓存失败：'+e.message)}}
async function exportAllSources(){const old=$('ip-display').value;const mode=$('export-mode').value;setResult('正在批量拉取并合并全部真实源...');try{const res=await fetch('/api/export-all?mode='+encodeURIComponent(mode));setResult(await res.text());switchPage('sources')}catch(e){setResult(old);alert('导出失败：'+e.message)}}
async function exportSingleSource(id){const mode=$('export-mode')?.value||'tagged';try{const res=await fetch('/api/export-all?mode='+encodeURIComponent(mode)+'&ID='+encodeURIComponent(id)+'&refresh=1');const text=await res.text();if(!res.ok)throw new Error(text||res.statusText);downloadBlob(text,`bestip-${safeFilePart(id)}-${mode}-${stamp()}.${mode==='csv'?'csv':'txt'}`,mode==='csv'?'text/csv;charset=utf-8':'text/plain;charset=utf-8');toast('已导出单源：'+id)}catch(e){alert('单源导出失败：'+e.message)}}
async function viewRawSource(id){setResult('正在读取原始返回...');try{const res=await fetch('/api/source-raw?ID='+encodeURIComponent(id),{headers:adminHeaders()});const data=await res.json();if(!res.ok)throw new Error(data.error||'读取失败');setResult(data.text||'');currentRawData=data.text||'';currentExtractMode=false;toast(`原始返回：HTTP ${data.status||'-'} · ${data.bytes||0} bytes · ${data.ms}ms`);switchPage('sources')}catch(e){setResult('读取原始返回失败：'+e.message)}}
async function viewParsedSource(id){setResult('正在解析该源...');try{const res=await fetch('/api/source-parse?ID='+encodeURIComponent(id));const data=await res.json();if(!res.ok)throw new Error(data.error||'解析失败');setResult((data.lines||[]).join('\n'));currentRawData=(data.lines||[]).join('\n');currentExtractMode=false;toast(`解析结果：${data.parsedLines||0} 行 · 地址 ${data.addressLines||0} 条 · ${data.ms}ms`);switchPage('sources')}catch(e){setResult('解析源失败：'+e.message)}}
async function exportCategory(category){const mode=$('export-mode')?.value||'tagged';try{const res=await fetch('/api/export-all?mode='+encodeURIComponent(mode)+'&category='+encodeURIComponent(category)+'&refresh=1');const text=await res.text();if(!res.ok)throw new Error(text||res.statusText);downloadBlob(text,`bestip-${safeFilePart(category)}-${mode}-${stamp()}.${mode==='csv'?'csv':'txt'}`,mode==='csv'?'text/csv;charset=utf-8':'text/plain;charset=utf-8');toast('已导出分类：'+category)}catch(e){alert('分类导出失败：'+e.message)}}
function validIPv4(ip){const parts=String(ip||'').split('.').map(Number);return parts.length===4&&parts.every(n=>Number.isInteger(n)&&n>=0&&n<=255)}
function parseLineAddress(line,defaultPort=$('st-port')?.value||'443'){const text=String(line||'').trim();if(!text)return null;const main=text.split('#')[0].trim();const m=main.match(/((?:\d{1,3}\.){3}\d{1,3})(?::(\d{1,5}))?/);if(!m||!validIPv4(m[1]))return null;return{ip:m[1],port:m[2]||defaultPort,cc:'当前结果'}}
async function loadArtifactCandidates(port){try{const res=await fetch('/artifacts/latest/all.txt');if(!res.ok)return[];const text=await res.text();return extractUsefulLines(text).map(line=>parseLineAddress(line,port)).filter(Boolean)}catch{return[]}}
async function parseTestIps(){const lib=$('st-lib').value,port=$('st-port')?.value||'443';if(lib==='display')return extractUsefulLines($('ip-display').value).map(line=>parseLineAddress(line,port)).filter(Boolean).slice(0,1000);if(lib==='artifact'){const rows=await loadArtifactCandidates(port);return rows.length?rows.slice(0,1000):LOCAL_POOL.map(x=>({ip:x[0],port,cc:x[1]}))}const arr=lib==='cf'?[['173.245.48.1','CF'],['103.21.244.1','CF'],['103.22.200.1','CF'],['103.31.4.1','CF'],['141.101.64.1','CF'],['108.162.192.1','CF'],['188.114.96.1','CF'],['104.16.0.1','CF'],['104.17.0.1','CF'],['104.18.0.1','CF'],['104.19.0.1','CF']]:LOCAL_POOL;return arr.map(x=>({ip:x[0],port,cc:x[1]}))}
async function openSpeedtestPage(){try{const r=await fetch('/api/ip-check');const j=await r.json();$('client-info').textContent=`当前访问IP: ${j.ip} | 国家: ${j.country}`;$('vpn-warning').style.display=j.country==='CN'?'none':'block'}catch{$('client-info').textContent='当前访问IP: 检测失败 | 国家: -'}}
async function speedtestCandidates(){const seen=new Set();return (await parseTestIps()).filter(x=>{const key=`${x.ip}:${x.port}`;if(seen.has(key))return false;seen.add(key);return true})}async function exportSpeedtestCandidates(){const list=await speedtestCandidates();if(!list.length)return alert('没有可导出的候选 IP');const text=list.map(x=>x.ip).join('\n')+'\n';downloadBlob(text,`bestip-candidates-${$('st-port')?.value||443}-${stamp()}.txt`,'text/plain;charset=utf-8');toast(`已导出候选 IP：${list.length} 个`)}function exportCfstCommand(){const port=$('st-port')?.value||443;const cmd=[`# 1. 先在页面导出 bestip-candidates-${port}.txt`,`# 2. 使用 CloudflareSpeedTest / cfst 原生工具测速`,`CloudflareST -f bestip-candidates-${port}.txt -o bestip-cfst-result.csv -tp ${port} -n 200 -tll 200 -tl 800`,`# 3. 回到页面点击“导入测速 CSV”，选择 bestip-cfst-result.csv`].join('\n')+'\n';downloadBlob(cmd,`bestip-cfst-command-${port}-${stamp()}.sh`,'text/plain;charset=utf-8');toast('已导出 cfst 命令模板')}function parseCfstRows(text){const lines=text.split(/\r?\n/).map(x=>x.trim()).filter(Boolean);if(!lines.length)return[];const split=line=>line.includes('\t')?line.split('\t'):line.split(',');const first=split(lines[0]).map(x=>x.trim().toLowerCase());const hasHeader=first.some(x=>['ip','地址','latency','延迟','端口','port'].includes(x));const rows=hasHeader?lines.slice(1):lines;const idx=nameList=>first.findIndex(h=>nameList.some(n=>h.includes(n)));const ipIdx=hasHeader?Math.max(idx(['ip','地址']),0):0;const portIdx=hasHeader?idx(['port','端口']):-1;const latencyIdx=hasHeader?idx(['latency','延迟','平均延迟','丢包前延迟']):-1;return rows.map(line=>{const cols=split(line).map(x=>x.trim());const ip=(cols[ipIdx]||'').match(/(?:\d{1,3}\.){3}\d{1,3}/)?.[0];if(!ip)return null;const port=(portIdx>=0&&cols[portIdx])||$('st-port')?.value||'443';let latency=latencyIdx>=0?parseFloat(String(cols[latencyIdx]).replace(/ms/i,'')):NaN;if(!Number.isFinite(latency)){const hit=cols.map(c=>String(c).match(/(\d+(?:\.\d+)?)\s*ms/i)).find(Boolean);latency=hit?parseFloat(hit[1]):9999}return{ip,port:String(port),cc:'CFST',latency}}).filter(Boolean).sort((a,b)=>a.latency-b.latency)}async function handleCfstFile(file){if(!file)return;const text=await file.text();const rows=parseCfstRows(text);if(!rows.length)return alert('未从 CSV 中解析到测速结果');renderSpeedtestResults(rows.slice(0,500));$('st-progress').style.display='block';$('st-bar').style.width='100%';$('st-status').textContent=`✅ 已导入原生测速结果：${rows.length} 个`;const counts={CFST:rows.length};$('st-country').innerHTML='<option value="all">全部显示 ('+rows.length+')</option>'+Object.entries(counts).map(([cc,n])=>`<option value="${cc}">${cc} (${n})</option>`).join('');toast(`已导入测速结果：${rows.length} 个`)}
function readSpeedtestHistory(){try{return JSON.parse(localStorage.getItem(SPEEDTEST_HISTORY_KEY)||'[]')}catch{return[]}}function writeSpeedtestHistory(list){localStorage.setItem(SPEEDTEST_HISTORY_KEY,JSON.stringify(list.slice(0,30)))}function speedtestHistoryTitle(item){const d=new Date(item.at);return `${d.toLocaleString()} · ${item.count} 个 · 平均 ${Math.round(item.avg||0)}ms`}function saveSpeedtestHistory(){const list=filteredSpeedtestResults();if(!list.length)return alert('当前没有可保存的测速结果');const stats=speedtestStats(list);const item={id:Date.now(),at:new Date().toISOString(),port:$('st-port')?.value||'443',filter:{cc:$('st-country')?.value||'all',maxLatency:$('st-max-latency')?.value||'0',topN:$('st-top-n')?.value||'0',format:$('st-export-format')?.value||'tagged'},count:list.length,min:stats.min,max:stats.max,avg:stats.avg,results:list};const history=readSpeedtestHistory();history.unshift(item);writeSpeedtestHistory(history);renderSpeedtestHistory();toast(`已保存测速历史：${list.length} 个`)}function compareSpeedtestHistory(item){const history=readSpeedtestHistory();const prev=history.find(x=>x.id!==item.id);if(!prev)return '暂无可对比历史';const oldMap=new Map((prev.results||[]).map(r=>[`${r.ip}:${r.port}`,r]));let better=0,worse=0,same=0,newOnes=0;for(const r of item.results||[]){const old=oldMap.get(`${r.ip}:${r.port}`);if(!old){newOnes++;continue}const diff=(Number(r.latency)||0)-(Number(old.latency)||0);if(diff<-10)better++;else if(diff>10)worse++;else same++}return `较上一条：变好 ${better} · 变差 ${worse} · 持平 ${same} · 新增 ${newOnes}`}function restoreSpeedtestHistory(id){const item=readSpeedtestHistory().find(x=>String(x.id)===String(id));if(!item)return;renderSpeedtestResults(item.results||[]);$('st-progress').style.display='block';$('st-bar').style.width='100%';$('st-status').textContent=`✅ 已恢复历史测速：${speedtestHistoryTitle(item)}`;const counts={};(item.results||[]).forEach(x=>counts[x.cc]=(counts[x.cc]||0)+1);$('st-country').innerHTML='<option value="all">全部显示 ('+(item.results||[]).length+')</option>'+Object.entries(counts).map(([cc,n])=>`<option value="${cc}">${cc} (${n})</option>`).join('');toast('已恢复历史测速结果')}function exportSpeedtestHistory(){const history=readSpeedtestHistory();if(!history.length)return alert('暂无测速历史');downloadBlob(JSON.stringify(history,null,2),`bestip-speedtest-history-${stamp()}.json`,'application/json;charset=utf-8');toast(`已导出测速历史：${history.length} 条`)}function clearSpeedtestHistory(){if(!confirm('确定清空全部测速历史？'))return;writeSpeedtestHistory([]);renderSpeedtestHistory();toast('已清空测速历史')}function renderSpeedtestHistory(){const panel=$('st-history-panel'),list=$('st-history-list'),sum=$('st-history-summary');if(!panel||!list||!sum)return;const history=readSpeedtestHistory();sum.textContent=history.length?`${history.length} 条历史，最多保留 30 条`:'暂无历史';if(!history.length){list.innerHTML='<div class="archive-empty">暂无测速历史。完成测速或导入 CSV 后，点击“保存历史”。</div>';return}list.innerHTML=history.map(item=>`<div class="speed-history-item"><div><b>${speedtestHistoryTitle(item)}</b><span>${compareSpeedtestHistory(item)}</span><small>端口 ${item.port||'-'} · 筛选 ${item.filter?.cc||'all'} · 阈值 ${item.filter?.maxLatency||0}ms · Top ${item.filter?.topN||0}</small></div><div class="archive-actions"><button class="btn blue" data-st-restore="${item.id}">恢复</button><button class="btn purple" data-st-export-one="${item.id}">导出</button></div></div>`).join('')}function exportOneSpeedtestHistory(id){const item=readSpeedtestHistory().find(x=>String(x.id)===String(id));if(!item)return;downloadBlob(JSON.stringify(item,null,2),`bestip-speedtest-${item.id}.json`,'application/json;charset=utf-8')}
function speedtestStats(list){if(!list.length)return{count:0,min:0,max:0,avg:0};const l=list.map(x=>Number(x.latency)||0);return{count:list.length,min:Math.min(...l),max:Math.max(...l),avg:l.reduce((a,b)=>a+b,0)/l.length}}function filteredSpeedtestResults(){const cc=$('st-country')?.value||'all';const max=Number($('st-max-latency')?.value||0);const top=Number($('st-top-n')?.value||0);let list=stResults.slice().sort((a,b)=>a.latency-b.latency);if(cc!=='all')list=list.filter(r=>r.cc===cc);if(max>0)list=list.filter(r=>Number(r.latency)<=max);if(top>0)list=list.slice(0,top);return list}function updateSpeedtestQualitySummary(){const all=speedtestStats(stResults);const filtered=speedtestStats(filteredSpeedtestResults());const box=$('st-quality-summary');if(!box)return;box.textContent=all.count?`测速结果统计：全部 ${all.count} 个，最快 ${Math.round(all.min)}ms，最慢 ${Math.round(all.max)}ms，平均 ${Math.round(all.avg)}ms；当前筛选 ${filtered.count} 个`:'测速结果统计：暂无'}function applySpeedtestVisualFilter(){const keys=new Set(filteredSpeedtestResults().map(r=>`${r.ip}:${r.port}`));document.querySelectorAll('#st-results .pill').forEach(p=>p.style.display=keys.has(p.dataset.key)?'inline-flex':'none');updateSpeedtestQualitySummary()}function exportFilteredSpeedtest(){const list=filteredSpeedtestResults();if(!list.length)return alert('当前筛选条件下没有可导出的测速结果');const fmt=$('st-export-format')?.value||'tagged';let text='',mime='text/plain;charset=utf-8',ext='txt';if(fmt==='csv'){mime='text/csv;charset=utf-8';ext='csv';text='ip,port,region,latency_ms\n'+list.map(r=>`${r.ip},${r.port},${REGION_MAP[r.cc]||r.cc},${Math.round(r.latency)}`).join('\n')+'\n'}else if(fmt==='plain'){text=list.map(r=>`${r.ip}:${r.port}`).join('\n')+'\n'}else{text=list.map(r=>`${r.ip}:${r.port}#${REGION_MAP[r.cc]||r.cc}_${Math.round(r.latency)}ms`).join('\n')+'\n'}downloadBlob(text,`bestip-speedtest-filtered-${fmt}-${stamp()}.${ext}`,mime);toast(`已导出筛选结果：${list.length} 个`)}
function renderSpeedtestResults(results){stResults=results.slice().sort((a,b)=>a.latency-b.latency);$('st-results').innerHTML='';for(const r of stResults){const p=document.createElement('span');p.className='pill';p.dataset.cc=r.cc;p.dataset.key=`${r.ip}:${r.port}`;p.dataset.latency=String(r.latency);p.innerHTML=`${r.ip}:${r.port} <b>${Math.round(r.latency)}ms</b> <span style="opacity:.6">[${REGION_MAP[r.cc]||r.cc}${r.colo?'/'+r.colo:''}]</span>`;$('st-results').appendChild(p)}$('st-save').style.display=stResults.length?'inline-block':'none';applySpeedtestVisualFilter()}
function ipv4ToHexHost(ip){return ip.split('.').map(x=>Number(x).toString(16).padStart(2,'0')).join('')}
function parseTrace(text){const obj={};String(text||'').split(/\n/).forEach(line=>{const i=line.indexOf('=');if(i>0)obj[line.slice(0,i).trim()]=line.slice(i+1).trim()});return obj}
async function loadCfLocations(){try{const r=await fetch('https://speed.cloudflare.com/locations',{cache:'force-cache'});if(!r.ok)return{};const rows=await r.json();const map={};rows.forEach(x=>{if(x.iata)map[x.iata]=x});return map}catch{return{}}}
async function browserLatencyTestOne(item,nipDomain,timeout,locations){const ip=item.ip,port=item.port||$('st-port')?.value||'443';if(!validIPv4(ip))return null;const url=`https://${ipv4ToHexHost(ip)}.${nipDomain}:${port}/cdn-cgi/trace`;let controller=new AbortController(),timer=setTimeout(()=>controller.abort(),timeout);try{try{await fetch(url,{signal:controller.signal,mode:'cors',cache:'no-store'});}catch{}clearTimeout(timer);controller=new AbortController();timer=setTimeout(()=>controller.abort(),timeout);const start=performance.now();const res=await fetch(url,{signal:controller.signal,mode:'cors',cache:'no-store'});const latency=performance.now()-start;clearTimeout(timer);if(!res.ok)return null;const trace=parseTrace(await res.text());if(!trace.colo)return null;const loc=locations[trace.colo]||{};const cc=loc.cca2||item.cc||trace.colo||'CF';return{ip,port:String(port),cc,colo:trace.colo,latency,responseIp:trace.ip||'',type:(trace.ip===ip||String(trace.ip||'').includes(':'))?'proxy':'official'}}catch(e){clearTimeout(timer);return null}}
async function startNativeSpeedtest(){if(isTesting)return;isTesting=true;abortSpeedtest=false;stResults=[];$('st-progress').style.display='block';$('st-results').innerHTML='';$('st-save').style.display='none';$('st-bar').style.width='0%';const threads=parseInt($('st-threads').value,10)||8;const limit=Math.max(1,Math.min(1000,Number($('st-limit')?.value||256)));const nipDomain=($('st-nip-domain')?.value||DEFAULT_NIP_DOMAIN).trim().replace(/^https?:\/\//,'').replace(/\/.*$/,'')||DEFAULT_NIP_DOMAIN;const ips=(await parseTestIps()).slice(0,limit);const counts={};ips.forEach(x=>counts[x.cc]=(counts[x.cc]||0)+1);$('st-country').innerHTML='<option value="all">全部显示 ('+ips.length+')</option>'+Object.entries(counts).map(([cc,n])=>`<option value="${cc}">${cc} (${n})</option>`).join('');$('st-status').textContent=`正在执行浏览器延迟测试... (0/${ips.length}) · ${nipDomain}`;const locations=await loadCfLocations();let done=0;const results=[];let index=0;async function worker(){while(index<ips.length&&!abortSpeedtest){const item=ips[index++];const r=await browserLatencyTestOne(item,nipDomain,5000,locations);if(r){results.push(r);renderSpeedtestResults(results)}done++;$('st-bar').style.width=(done/ips.length*100).toFixed(1)+'%';$('st-status').textContent=`浏览器延迟测试中... ${done}/${ips.length} · 可用 ${results.length} · ${nipDomain}`}}try{await Promise.all(Array.from({length:Math.min(threads,ips.length)},worker));renderSpeedtestResults(results);$('st-bar').style.width='100%';$('st-status').textContent=`${abortSpeedtest?'⏹ 已停止':'✅ 浏览器延迟测试完成'}：测试 ${done}/${ips.length} 个，连通 ${stResults.length} 个`;toast('浏览器在线延迟测试完成')}finally{isTesting=false;abortSpeedtest=false}}
function stopSpeedtest(){abortSpeedtest=true;$('st-status').textContent='正在停止测速...'}
function saveNativeSpeedtest(){const list=filteredSpeedtestResults();if(!list.length)return alert('当前筛选条件下没有可用IP');const fmt=$('st-export-format')?.value||'tagged';let text='';if(fmt==='csv')text='ip,port,region,latency_ms\n'+list.map(r=>`${r.ip},${r.port},${REGION_MAP[r.cc]||r.cc},${Math.round(r.latency)}`).join('\n');else if(fmt==='plain')text=list.map(r=>`${r.ip}:${r.port}`).join('\n');else text=list.map(r=>`${r.ip}:${r.port}#${REGION_MAP[r.cc]||r.cc}_${Math.round(r.latency)}ms`).join('\n');setResult($('ip-display').value.trim()?$('ip-display').value.trim()+'\n'+text:text);switchPage('sources')}function openAdminPage(){adminConfig=JSON.parse(JSON.stringify(globalConfig));renderAdmin()}
function renderAdmin(){const box=$('admin-list');box.innerHTML='';adminConfig.forEach((group,gi)=>{const wrap=document.createElement('div');wrap.className='group-block';wrap.innerHTML=`<div class="group-head"><button class="node-btn" data-toggle-group="${gi}">▶</button><input class="grow" value="${esc(group.groupName)}" data-group-name="${gi}" placeholder="主分类名称"><button class="node-btn green" data-add-node="${gi}">+ 子线路</button><button class="node-btn red" data-remove-group="${gi}">删除</button></div><div id="admin-nodes-${gi}" style="display:none"></div>`;box.appendChild(wrap);renderAdminNodes(gi)})}
function renderAdminNodes(gi){const box=$('admin-nodes-'+gi);box.innerHTML='';(adminConfig[gi].nodes||[]).forEach((node,ni)=>{const row=document.createElement('div');row.className='node-line';row.innerHTML=`<input class="grow" value="${esc(node.ID)}" data-node-id="${gi}:${ni}" placeholder="按钮名称"><input class="grow" value="${esc(node.url||'')}" data-node-url="${gi}:${ni}" placeholder="数据源 URL / local:key"><label class="hint"><input type="checkbox" ${node.extract?'checked':''} data-node-extract="${gi}:${ni}"> 提取IP</label><button class="node-btn red" data-remove-node="${gi}:${ni}">删除</button>`;box.appendChild(row)})}
function expandAllAdmin(open){adminConfig.forEach((_,i)=>{$('admin-nodes-'+i).style.display=open?'block':'none'})}
const SAVE_ARCHIVE_KEY='bestip-config-save-archives';function loadSaveArchives(){try{return JSON.parse(localStorage.getItem(SAVE_ARCHIVE_KEY)||'[]')}catch{return []}}function setSaveArchives(archives){localStorage.setItem(SAVE_ARCHIVE_KEY,JSON.stringify(archives.slice(0,20)))}function autoArchiveSavePreview(changes){try{const archives=loadSaveArchives();archives.unshift({timestamp:new Date().toISOString(),before:globalConfig,toSave:JSON.parse(pendingSaveSnapshot),summary:formatConfigChangeSummary(changes)});localStorage.setItem(SAVE_ARCHIVE_KEY,JSON.stringify(archives.slice(0,20)));return Math.min(archives.length,20)}catch(e){console.warn('save archive failed',e);return 0}}function exportSaveArchive(){const archives=loadSaveArchives();if(!archives.length)return alert('暂无本地快照档案');downloadBlob(JSON.stringify(archives,null,2)+'\n',`bestip-config-local-archives-${stamp()}.json`,'application/json;charset=utf-8')}function archiveMatchesFilter(archive,filter){const summary=String(archive.summary||'');if(filter==='removedNodes')return summary.includes('删除线路')&&!summary.includes('删除线路：0');if(filter==='changedUrls')return summary.includes('URL 变更')&&!summary.includes('URL 变更：0');if(filter==='addedGroups')return summary.includes('新增分类')&&!summary.includes('新增分类：0');if(filter==='removedGroups')return summary.includes('删除分类')&&!summary.includes('删除分类：0');return true}function renderArchivePanel(){const box=$('config-archive-panel');if(!box)return;box.style.display='block';if(!box.dataset.ready){box.innerHTML=`<h4>本地快照档案</h4><div class="hint">保存在浏览器 localStorage，最多 20 条。恢复配置只会写入编辑区，并会重新生成保存预览；仍需点击“确认保存到线上配置”才会生效。</div><div class="toolbar mini"><input class="grow" id="archive-search" placeholder="搜索时间或变更摘要"><select id="archive-filter"><option value="all">全部快照</option><option value="removedNodes">包含删除线路</option><option value="changedUrls">包含 URL 变更</option><option value="addedGroups">包含新增分类</option><option value="removedGroups">包含删除分类</option></select><button class="btn blue" id="btn-archive-search-clear">清空搜索</button></div><div id="archive-restore-preview" class="save-preview" style="display:none"></div><div id="archive-list"></div>`;box.dataset.ready='1'}renderArchiveList()}function renderArchiveList(){const listBox=$('archive-list');if(!listBox)return;const archives=loadSaveArchives();const q=($('archive-search')?.value||'').trim().toLowerCase();const filter=$('archive-filter')?.value||'all';const filtered=archives.map((archive,i)=>({archive,i})).filter(({archive})=>{const hay=[archive.timestamp,archive.summary].join('\n').toLowerCase();return (!q||hay.includes(q))&&archiveMatchesFilter(archive,filter)});const item=({archive,i})=>`<div class="archive-item"><div class="archive-item-head"><div><b>快照 #${i+1}</b><div class="hint">${esc(archive.timestamp||'未知时间')}</div></div><span class="hint">before: ${Array.isArray(archive.before)?archive.before.length:0} 类 / toSave: ${Array.isArray(archive.toSave)?archive.toSave.length:0} 类</span></div><pre class="archive-summary">${esc(String(archive.summary||'无摘要'))}</pre><div class="archive-actions"><button class="btn purple" data-archive-export="${i}">导出单条</button><button class="btn blue" data-archive-restore-before="${i}">恢复保存前配置</button><button class="btn blue" data-archive-restore-tosave="${i}">恢复待保存配置</button><button class="btn red" data-archive-delete="${i}">删除</button></div></div>`;listBox.innerHTML=`<div class="archive-actions"><button class="btn purple" id="btn-archive-export-all">导出全部档案</button><button class="btn red" id="btn-archive-clear">清空全部档案</button><button class="btn blue" id="btn-archive-close">关闭</button></div><div class="archive-filter-summary">共 ${archives.length} 条，当前显示 ${filtered.length} 条。</div>${filtered.length?filtered.map(item).join(''):'<div class="archive-empty">没有匹配的本地快照档案。</div>'}`}
function renderArchiveRestorePreview(){const box=$('archive-restore-preview');if(!box||!pendingArchiveRestore)return;const {changes,key,index}=pendingArchiveRestore;box.style.display='block';const stat=(label,value)=>`<div class="save-preview-stat"><span>${label}</span><b>${value}</b></div>`;const list=(title,items)=>items.length?`<div><b>${title}</b><ul>${items.slice(0,20).map(item=>`<li>${esc(item)}</li>`).join('')}${items.length>20?'<li>...</li>':''}</ul></div>`:'';box.innerHTML=`<h4>恢复快照前差异预览</h4><div class="hint">目标：快照 #${index+1} 的 ${key==='before'?'保存前配置':'待保存配置'}。请确认当前编辑区与目标快照的差异后再恢复；恢复后仍需在保存预览中确认提交线上配置。</div><div class="save-preview-grid">${stat('总变更',changes.totalChanges)}${stat('新增分类',changes.addedGroups.length)}${stat('删除分类',changes.removedGroups.length)}${stat('新增线路',changes.addedNodes.length)}${stat('删除线路',changes.removedNodes.length)}${stat('URL 变更',changes.changedUrls.length)}${stat('提取模式变更',changes.changedExtract.length)}${stat('未变化线路',changes.unchangedNodes)}</div>${list('新增分类',changes.addedGroups)}${list('删除分类',changes.removedGroups)}${list('新增线路',changes.addedNodes)}${list('删除线路',changes.removedNodes)}${list('URL 变更',changes.changedUrls)}${list('提取模式变更',changes.changedExtract)}<div class="save-preview-actions"><button class="btn green" id="btn-archive-restore-confirm">确认恢复到编辑区</button><button class="btn purple" id="btn-archive-restore-export">导出目标快照</button><button class="btn blue" id="btn-archive-restore-cancel">取消恢复</button></div>`}function clearArchiveRestorePreview(){pendingArchiveRestore=null;const box=$('archive-restore-preview');if(box){box.style.display='none';box.innerHTML=''}}function hideArchivePanel(){clearArchiveRestorePreview();const box=$('config-archive-panel');if(box){box.style.display='none';box.innerHTML='';delete box.dataset.ready}}function exportArchiveRestoreTarget(){if(!pendingArchiveRestore)return alert('没有待恢复快照');downloadBlob(JSON.stringify(pendingArchiveRestore.config,null,2)+'\n',`bestip-config-restore-target-${pendingArchiveRestore.key}-${stamp()}.json`,'application/json;charset=utf-8')}function confirmArchiveRestore(){if(!pendingArchiveRestore)return alert('没有待恢复快照');adminConfig=pendingArchiveRestore.config;clearArchiveRestorePreview();clearImportPreview();clearSavePreview();renderAdmin();void saveConfig();toast('已恢复快照配置到编辑区，请在保存预览中确认提交')}function exportArchiveItem(i){const archives=loadSaveArchives();const item=archives[i];if(!item)return alert('快照不存在');downloadBlob(JSON.stringify(item,null,2)+'\n',`bestip-config-archive-${i+1}-${stamp()}.json`,'application/json;charset=utf-8')}function restoreArchiveConfig(i,key){const archives=loadSaveArchives();const item=archives[i];if(!item||!Array.isArray(item[key]))return alert('快照配置不存在');const dryRun=validateConfigDetailed(item[key],{normalize:true});if(!dryRun.ok)return alert('快照配置校验失败：\n'+dryRun.errors.join('\n'));const changes=summarizeConfigChanges(adminConfig,dryRun.config);pendingArchiveRestore={index:i,key,config:dryRun.config,changes};renderArchiveRestorePreview();if(!hasConfigChanges(changes))toast('目标快照与当前编辑区一致')}function deleteArchiveItem(i){const archives=loadSaveArchives();if(!archives[i])return alert('快照不存在');archives.splice(i,1);setSaveArchives(archives);pendingSaveArchiveCount=archives.length;clearArchiveRestorePreview();renderArchivePanel()}function clearAllArchives(){if(!confirm('确认清空全部本地快照档案？'))return;setSaveArchives([]);pendingSaveArchiveCount=0;clearArchiveRestorePreview();renderArchivePanel()}
function assertSavePreviewFresh(){if(!pendingSaveSnapshot)return false;return JSON.stringify(adminConfig)===pendingSaveSnapshot}function exportSaveBeforeSnapshot(){downloadBlob(JSON.stringify(globalConfig,null,2)+'\n',`bestip-config-before-save-${stamp()}.json`,'application/json;charset=utf-8')}function exportSaveAfterSnapshot(){if(!pendingSaveSnapshot)return alert('请先生成保存预览');if(!assertSavePreviewFresh())return alert('配置已在预览后发生变化，请重新点击保存配置生成最新摘要');downloadBlob(JSON.stringify(JSON.parse(pendingSaveSnapshot),null,2)+'\n',`bestip-config-to-save-${stamp()}.json`,'application/json;charset=utf-8')}function exportSaveChangeSummary(){if(!pendingSaveChanges)return alert('请先生成保存预览');if(!assertSavePreviewFresh())return alert('配置已在预览后发生变化，请重新点击保存配置生成最新摘要');downloadBlob(formatConfigChangeSummary(pendingSaveChanges)+'\n',`bestip-config-change-summary-${stamp()}.txt`,'text/plain;charset=utf-8')}function renderSavePreview(changes){const box=$('config-save-preview');if(!box)return;box.style.display='block';const stat=(label,value)=>`<div class="save-preview-stat"><span>${label}</span><b>${value}</b></div>`;const list=(title,items)=>items.length?`<div><b>${title}</b><ul>${items.slice(0,20).map(item=>`<li>${esc(item)}</li>`).join('')}${items.length>20?'<li>...</li>':''}</ul></div>`:'';box.innerHTML=`<h4>保存配置前变更摘要</h4><div class="hint">请确认本次变更后再保存到线上配置。系统已自动写入本地快照档案${pendingSaveArchiveCount?`（当前保留 ${pendingSaveArchiveCount} 条）`:''}；也可手动导出保存前快照、待保存快照和变更摘要。预览生成后如继续编辑，需要重新点击“保存配置”生成摘要。</div><div class="save-preview-grid">${stat('总变更',changes.totalChanges)}${stat('新增分类',changes.addedGroups.length)}${stat('删除分类',changes.removedGroups.length)}${stat('新增线路',changes.addedNodes.length)}${stat('删除线路',changes.removedNodes.length)}${stat('URL 变更',changes.changedUrls.length)}${stat('提取模式变更',changes.changedExtract.length)}${stat('未变化线路',changes.unchangedNodes)}</div>${list('新增分类',changes.addedGroups)}${list('删除分类',changes.removedGroups)}${list('新增线路',changes.addedNodes)}${list('删除线路',changes.removedNodes)}${list('URL 变更',changes.changedUrls)}${list('提取模式变更',changes.changedExtract)}<div class="save-preview-actions"><button class="btn purple" id="btn-save-export-before">导出保存前快照</button><button class="btn purple" id="btn-save-export-after">导出待保存快照</button><button class="btn purple" id="btn-save-export-summary">导出变更摘要</button><button class="btn purple" id="btn-save-export-archive">导出本地快照档案</button><button class="btn green" id="btn-save-apply">确认保存到线上配置</button><button class="btn blue" id="btn-save-cancel">取消保存</button></div>`}function clearSavePreview(){pendingSaveSnapshot='';pendingSaveChanges=null;pendingSaveArchiveCount=loadSaveArchives().length;const box=$('config-save-preview');if(box){box.style.display='none';box.innerHTML=''}}async function submitConfigSave(){if(!pendingSaveSnapshot)return alert('请先生成保存预览');const current=JSON.stringify(adminConfig);if(current!==pendingSaveSnapshot){clearSavePreview();return alert('配置已在预览后发生变化，请重新点击保存配置生成最新摘要')}const res=await fetch('/api/config',{method:'POST',headers:adminHeaders({'content-type':'application/json'}),body:current});const data=await res.json();if(!res.ok)return alert(data.error||'保存失败');globalConfig=JSON.parse(current);healthData=null;clearSavePreview();renderMainNav();alert('配置已保存')}async function saveConfig(){const err=validateConfig(adminConfig);if(err)return alert('配置校验失败：'+err);const changes=summarizeConfigChanges(globalConfig,adminConfig);if(!hasConfigChanges(changes)){clearSavePreview();return alert('配置没有变化，无需保存')}pendingSaveSnapshot=JSON.stringify(adminConfig);pendingSaveChanges=changes;pendingSaveArchiveCount=autoArchiveSavePreview(changes);renderSavePreview(changes);toast('已生成保存配置前变更摘要，并已自动写入本地快照档案')}
function renderImportPreview(result,fileName='配置文件'){const box=$('config-import-preview');if(!box)return;box.style.display='block';box.classList.toggle('bad',!result.ok);const stat=(label,value)=>`<div class="import-preview-stat"><span>${label}</span><b>${value}</b></div>`;const list=(title,items)=>items.length?`<div><b>${title}</b><ul>${items.slice(0,20).map(item=>`<li>${esc(item)}</li>`).join('')}${items.length>20?'<li>...</li>':''}</ul></div>`:'';box.innerHTML=`<h4>${result.ok?'导入 dry-run 校验通过':'导入 dry-run 校验失败'}：${esc(fileName)}</h4><div class="hint">${result.ok?'请确认摘要后应用到配置中心，仍需点击“保存配置”才会写入线上配置。':'请修复错误后重新选择配置文件。'}</div><div class="import-preview-grid">${stat('分类',result.summary.groups)}${stat('线路',result.summary.nodes)}${stat('远程源',result.summary.remote)}${stat('本地源',result.summary.local)}${stat('提取模式',result.summary.extract)}</div>${list('错误',result.errors)}${list('警告',result.warnings)}<div class="import-preview-actions">${result.ok?'<button class="btn green" id="btn-import-apply">确认应用导入</button>':''}<button class="btn blue" id="btn-import-cancel">取消导入</button></div>`}function clearImportPreview(){pendingImportConfig=null;const box=$('config-import-preview');if(box){box.style.display='none';box.innerHTML='';box.classList.remove('bad')}}function applyImportPreview(){if(!pendingImportConfig)return alert('没有待应用的导入配置');adminConfig=pendingImportConfig;clearImportPreview();clearSavePreview();renderAdmin();alert('已应用导入配置，请点击保存配置生效')}function exportConfig(){downloadBlob(JSON.stringify(adminConfig,null,2)+'\n',`bestip-config-${stamp()}.json`,'application/json;charset=utf-8')}function importConfig(){$('config-file').value='';$('config-file').click()}async function handleConfigFile(file){if(!file)return;try{const data=JSON.parse(await file.text());const dryRun=validateConfigDetailed(data,{normalize:true});pendingImportConfig=dryRun.ok?dryRun.config:null;renderImportPreview(dryRun,file.name||'配置文件')}catch(e){pendingImportConfig=null;renderImportPreview({ok:false,errors:['JSON 解析失败：'+e.message],warnings:[],summary:{groups:0,nodes:0,remote:0,local:0,extract:0}},file.name||'配置文件')}}async function restoreDefaultConfig(){if(!confirm('确认恢复默认真实源配置？'))return;const res=await fetch('/default-config.json');const data=await res.json();const dryRun=validateConfigDetailed(data,{normalize:true});if(!dryRun.ok)return alert('默认配置校验失败：\n'+dryRun.errors.join('\n'));adminConfig=dryRun.config;clearImportPreview();clearSavePreview();renderAdmin();alert('已恢复默认真实源，请点击保存配置生效')}
async function copyResult(){await navigator.clipboard.writeText($('ip-display').value);alert('已复制 '+countLines($('ip-display').value)+' 行')}function clearResult(){setResult('')}function downloadResult(){downloadBlob($('ip-display').value,`bestip-result-${stamp()}.txt`,'text/plain;charset=utf-8')}
function bindEvents(){document.querySelectorAll('.nav-item').forEach(b=>b.onclick=()=>switchPage(b.dataset.page));$('btn-health').onclick=()=>loadHealth(true);$('health-filter').onchange=renderHealthTable;$('health-group').onchange=renderHealthTable;$('btn-health-export').onclick=exportHealth;$('btn-export-all').onclick=exportAllSources;if($('source-search'))$('source-search').oninput=renderMainNav;if($('btn-source-search-clear'))$('btn-source-search-clear').onclick=()=>{$('source-search').value='';renderMainNav()};if($('btn-build-dataset'))$('btn-build-dataset').onclick=buildDataset;if($('btn-artifacts-refresh'))$('btn-artifacts-refresh').onclick=loadArtifacts;if($('artifact-links'))$('artifact-links').onclick=e=>{const name=e.target.dataset.artifactPreview;if(name)previewArtifact(name)};if($('btn-artifact-copy'))$('btn-artifact-copy').onclick=copyArtifactPreview;if($('btn-cache-refresh'))$('btn-cache-refresh').onclick=loadCacheStatus;if($('btn-cache-clear'))$('btn-cache-clear').onclick=clearCache;$('health-body').onclick=e=>{const id=e.target.dataset.recheck;if(id)recheckSource(id)};$('btn-copy').onclick=copyResult;$('btn-download').onclick=downloadResult;$('btn-clear-result').onclick=clearResult;$('ip-display').addEventListener('input',updateResultLines);$('btn-region-all').onclick=selectAllRegions;$('btn-global-fetch').onclick=fetchGlobalEdgetunnel;$('st-start').onclick=startNativeSpeedtest;if($('st-stop'))$('st-stop').onclick=stopSpeedtest;$('st-save').onclick=saveNativeSpeedtest;if($('st-export-filtered'))$('st-export-filtered').onclick=exportFilteredSpeedtest;if($('st-country'))$('st-country').onchange=applySpeedtestVisualFilter;if($('st-max-latency'))$('st-max-latency').oninput=applySpeedtestVisualFilter;if($('st-top-n'))$('st-top-n').oninput=applySpeedtestVisualFilter;if($('st-export-candidates'))$('st-export-candidates').onclick=exportSpeedtestCandidates;if($('st-export-cfst-command'))$('st-export-cfst-command').onclick=exportCfstCommand;if($('st-import-cfst'))$('st-import-cfst').onclick=()=>$('st-cfst-file').click();if($('st-cfst-file'))$('st-cfst-file').onchange=e=>handleCfstFile(e.target.files[0]);if($('st-save-history'))$('st-save-history').onclick=saveSpeedtestHistory;if($('st-toggle-history'))$('st-toggle-history').onclick=()=>{const p=$('st-history-panel');p.style.display=p.style.display==='none'?'block':'none';renderSpeedtestHistory()};if($('st-clear-history'))$('st-clear-history').onclick=clearSpeedtestHistory;if($('st-history-list'))$('st-history-list').onclick=e=>{if(e.target.dataset.stRestore)restoreSpeedtestHistory(e.target.dataset.stRestore);if(e.target.dataset.stExportOne)exportOneSpeedtestHistory(e.target.dataset.stExportOne)};$('btn-expand').onclick=()=>expandAllAdmin(true);$('btn-collapse').onclick=()=>expandAllAdmin(false);$('btn-add-group').onclick=()=>{adminConfig.push({groupName:'新分类',nodes:[]});clearSavePreview();renderAdmin()};$('btn-config-export').onclick=exportConfig;$('btn-config-import').onclick=importConfig;$('config-file').onchange=e=>handleConfigFile(e.target.files[0]);$('btn-default').onclick=restoreDefaultConfig;if($('btn-archive-toggle'))$('btn-archive-toggle').onclick=renderArchivePanel;$('btn-save-config').onclick=saveConfig;if($('config-import-preview'))$('config-import-preview').onclick=e=>{if(e.target.id==='btn-import-apply')applyImportPreview();if(e.target.id==='btn-import-cancel')clearImportPreview()};if($('config-save-preview'))$('config-save-preview').onclick=e=>{if(e.target.id==='btn-save-apply')submitConfigSave();if(e.target.id==='btn-save-cancel')clearSavePreview();if(e.target.id==='btn-save-export-before')exportSaveBeforeSnapshot();if(e.target.id==='btn-save-export-after')exportSaveAfterSnapshot();if(e.target.id==='btn-save-export-summary')exportSaveChangeSummary();if(e.target.id==='btn-save-export-archive')exportSaveArchive()};if($('config-archive-panel'))$('config-archive-panel').onclick=e=>{const t=e.target;if(t.id==='btn-archive-export-all')exportSaveArchive();if(t.id==='btn-archive-clear')clearAllArchives();if(t.id==='btn-archive-close')hideArchivePanel();if(t.id==='btn-archive-search-clear'){const q=$('archive-search');if(q)q.value='';const f=$('archive-filter');if(f)f.value='all';renderArchiveList()}if(t.id==='btn-archive-restore-confirm')confirmArchiveRestore();if(t.id==='btn-archive-restore-export')exportArchiveRestoreTarget();if(t.id==='btn-archive-restore-cancel')clearArchiveRestorePreview();if(t.dataset.archiveExport)exportArchiveItem(+t.dataset.archiveExport);if(t.dataset.archiveRestoreBefore)restoreArchiveConfig(+t.dataset.archiveRestoreBefore,'before');if(t.dataset.archiveRestoreTosave)restoreArchiveConfig(+t.dataset.archiveRestoreTosave,'toSave');if(t.dataset.archiveDelete)deleteArchiveItem(+t.dataset.archiveDelete)};if($('config-archive-panel')){$('config-archive-panel').oninput=e=>{if(e.target.id==='archive-search')renderArchiveList()};$('config-archive-panel').onchange=e=>{if(e.target.id==='archive-filter')renderArchiveList()}};$('admin-list').oninput=e=>{const t=e.target;if(t.dataset.groupName){adminConfig[+t.dataset.groupName].groupName=t.value;clearSavePreview()}if(t.dataset.nodeId){const[gi,ni]=t.dataset.nodeId.split(':').map(Number);adminConfig[gi].nodes[ni].ID=t.value;clearSavePreview()}if(t.dataset.nodeUrl){const[gi,ni]=t.dataset.nodeUrl.split(':').map(Number);adminConfig[gi].nodes[ni].url=t.value;clearSavePreview()}if(t.dataset.nodeExtract){const[gi,ni]=t.dataset.nodeExtract.split(':').map(Number);adminConfig[gi].nodes[ni].extract=t.checked;clearSavePreview()}};$('admin-list').onclick=e=>{const t=e.target;if(t.dataset.toggleGroup){const el=$('admin-nodes-'+t.dataset.toggleGroup);el.style.display=el.style.display==='none'?'block':'none'}if(t.dataset.addNode){const i=+t.dataset.addNode;adminConfig[i].nodes.push({ID:'新线路',url:'https://example.com/list.txt',extract:false});clearSavePreview();renderAdmin();$('admin-nodes-'+i).style.display='block'}if(t.dataset.removeGroup){adminConfig.splice(+t.dataset.removeGroup,1);clearSavePreview();renderAdmin()}if(t.dataset.removeNode){const[gi,ni]=t.dataset.removeNode.split(':').map(Number);adminConfig[gi].nodes.splice(ni,1);clearSavePreview();renderAdmin();$('admin-nodes-'+gi).style.display='block'}}}
async function init(){bindEvents();initRegionGrid();await loadNav();updateResultLines();loadArtifacts();loadCacheStatus();renderSpeedtestHistory();loadHealth(false)}
init();
